import { useEffect, useState } from "react";
import axios from "axios";
import Navbar from "../components/Navbar";

export default function CustomerDashboard(){

  const [workers,setWorkers]=useState([]);
  const [slots,setSlots]=useState([]);

  useEffect(()=>{
    axios.get("http://localhost:5000/api/auth/workers")
    .then(res=>setWorkers(res.data));
  },[]);

  const book=(w)=>{
    axios.post("http://localhost:5000/api/jobs/create",{
      workerName:w.name,
      labourId:w._id,
      workType:w.skills?.join(", "),
      timeSlots:slots,
      price:w.price
    });

    alert("Request Sent");
  }

  return(
    <div>
      <Navbar/>

      <h2>Find Workers</h2>

      <input placeholder="time 1" onChange={e=>setSlots([e.target.value])}/>
      <input placeholder="time 2" onChange={e=>setSlots([...slots,e.target.value])}/>
      <input placeholder="time 3" onChange={e=>setSlots([...slots,e.target.value])}/>
      <input placeholder="time 4" onChange={e=>setSlots([...slots,e.target.value])}/>

      {workers.map(w=>(
        <div key={w._id} style={{border:"1px solid #ddd",margin:10,padding:10}}>
          <h3>{w.name}</h3>
          <p>{w.skills?.join(", ")}</p>
          <p>₹{w.price}</p>

          <button onClick={()=>book(w)}>Book</button>
        </div>
      ))}
    </div>
  )
}
